from typing import Protocol


class Shape(Protocol):
    def area(self) -> float: ...
    def label(self) -> str: ...


def summary(shapes: list[Shape]) -> str:
    """One 'label=area' term per shape (area to 1 dp), joined by ', '."""
    return ", ".join(f"{s.label()}={s.area():.1f}" for s in shapes)

